INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'ca643df6-2496-4eea-a3e1-06da7ef94400', N'MANAGE_PAYROLL', N'Manage Pay Rolls', N'<p>The <strong>Add Payroll</strong> feature allows you to record salary payments for employees, including all salary components, deductions, and allowances.<br>It ensures accurate payroll management and proper accounting of employee payments.</p><hr><h2>Form Fields</h2><ul><li><p><strong>Employee *</strong>: Select the employee for whom the payroll is being added.</p></li><li><p><strong>Store/Location *</strong>: The branch or shop where the employee works (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Salary Month *</strong>: Month for which the salary is being paid.</p></li><li><p><strong>Salary Date *</strong>: Date on which the salary is processed (e.g., <em>9/13/2025</em>).</p></li><li><p><strong>Financial Year *</strong>: Select the relevant accounting year.</p></li></ul><h3>Salary Details</h3><ul><li><p><strong>Basic Salary *</strong>: Fixed salary component for the employee.</p></li><li><p><strong>Total Salary *</strong>: Total salary including all allowances and deductions.</p></li></ul><h3>Allowances &amp; Deductions</h3><ul><li><p><strong>Mobile Bill</strong> – Reimbursement for mobile expenses.</p></li><li><p><strong>Food Bill</strong> – Reimbursement for food or meal allowance.</p></li><li><p><strong>Bonus</strong> – Additional incentive payment.</p></li><li><p><strong>Commission</strong> – Commission for sales or performance.</p></li><li><p><strong>Festival Bonus</strong> – Special allowance for festivals.</p></li><li><p><strong>Travel Allowance</strong> – Reimbursement for travel expenses.</p></li><li><p><strong>Others</strong> – Any other allowances not listed above.</p></li><li><p><strong>Advance</strong> – Deduction for any salary advance taken by the employee.</p></li></ul><h3>Payment Details</h3><ul><li><p><strong>Payment Mode</strong> – Method used to pay the employee (e.g., Cash, Bank Transfer, Cheque).</p></li><li><p><strong>Cheque No</strong> – If payment is made via cheque, enter the cheque number.</p></li><li><p><strong>Attachment</strong> – Upload any supporting documents, if required.</p></li><li><p><strong>Note</strong> – Optional field for additional comments or remarks.</p></li></ul><hr><h2>Benefits of Add Payroll</h2><p> Ensures <strong>accurate recording of employee salaries</strong> with all allowances and deductions.<br> Supports <strong>audit and compliance</strong> by maintaining proper payroll documentation.<br> Helps in <strong>tracking employee payments</strong> and generating payroll reports.<br> Makes it easy to <strong>calculate total salary</strong> including bonuses and deductions.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T11:00:33.9498197' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'8e40aafe-f972-4009-a520-09a267028e9b', N'BALANCE_SHEET_REPORT', N'Balance Sheet Report', N'<p>The <strong>Balance Sheet Report</strong> shows the financial position of your business at a specific time.<br>It lists <strong>assets, liabilities, and equity</strong> for a selected <strong>store/location</strong> and <strong>financial year</strong>, ensuring that the accounting equation always balances.</p><hr><h2>Report Fields</h2><ul><li><p><strong>Store/Location:</strong> The shop or branch the report belongs to (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Financial Year:</strong> The accounting year selected for the report.</p></li></ul><h3>Key Sections</h3><ul><li><p><strong>Assets</strong><br>Resources owned by the business (e.g., cash, bank, inventory, receivables).<br><strong>Total Assets</strong> = Sum of all assets.</p></li><li><p><strong>Liabilities</strong><br>Obligations the business owes (e.g., loans, payables, taxes).<br><strong>Total Liabilities</strong> = Sum of all liabilities.</p></li><li><p><strong>Equity</strong><br>Owner’s share in the business (e.g., capital, retained earnings).<br><strong>Total Equity</strong> = Sum of equity accounts.</p></li><li><p><strong>Balance Check</strong><br><strong>Assets = Liabilities + Equity</strong><br>This ensures books are accurate and balanced.</p></li></ul><hr><h2>Benefits of the Balance Sheet Report</h2><p> Shows overall financial health of the business.<br> Helps assess liquidity, solvency, and net worth.<br> Essential for investors, auditors, and decision-making.<br> Ensures compliance with accounting standards.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:44:50.6547122' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'8efbddf7-8d8c-4bb9-81f3-1137537d0f23', N'CASH_BANK_REPORT', N'Cash Bank Report', N'<p>The <strong>Cash &amp; Bank Report</strong> provides a snapshot of available funds in both <strong>cash</strong> and <strong>bank accounts</strong> for a selected <strong>store/location</strong> and <strong>financial year</strong>.<br>It helps businesses monitor liquidity and maintain accurate financial records.</p><hr><h2>Report Fields</h2><ul><li><p><strong>Store/Location:</strong> The shop or branch the report belongs to (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Financial Year:</strong> The accounting year selected for the report.</p></li></ul><h3>Cash &amp; Bank Details</h3><ul><li><p><strong>Cash Total:</strong> Total amount of money held in cash registers or petty cash.</p></li><li><p><strong>Bank Total:</strong> Total balance held across linked bank accounts.</p></li><li><p><strong>Total Balance:</strong> Combined total of cash and bank balances.</p></li></ul><hr><h2>Benefits of the Cash &amp; Bank Report</h2><p> Real-time visibility of available funds.<br> Helps in daily cash flow management.<br> Ensures accurate reconciliation between cash, bank, and transactions.<br> Useful for financial planning and reporting.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:42:36.5912107' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'77cf0868-38d1-4122-abf3-2299339ef119', N'CUSTOMER_LADGER_LIST', N'Customer Ladgers', N'<p>The <strong>Customer Ledger List</strong> provides a detailed view of all transactions for each customer, helping you track payments, balances, and overdue amounts.<br>It is useful for managing receivables and maintaining accurate customer accounts.</p><hr><h2>Report Filters</h2><ul><li><p><strong>Date / Date Range:</strong> View transactions within a specific period.</p></li><li><p><strong>Reference:</strong> Filter by transaction reference number (e.g., invoice or receipt number).</p></li><li><p><strong>Customer:</strong> Select a specific customer to view their ledger entries.</p></li><li><p><strong>Store/Location:</strong> Choose the branch or shop associated with the transactions.</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Date:</strong> Date of the transaction.</p></li><li><p><strong>Amount:</strong> Transaction amount (payment received or invoice issued).</p></li><li><p><strong>Balance:</strong> Running balance for the customer after the transaction.</p></li><li><p><strong>Overdue:</strong> Amount that is overdue or pending payment.</p></li><li><p><strong>Reference:</strong> Transaction reference number or invoice number.</p></li><li><p><strong>Customer:</strong> Name of the customer.</p></li><li><p><strong>Store/Location:</strong> Branch or shop where the transaction occurred.</p></li><li><p><strong>Description:</strong> Brief description of the transaction (e.g., product sold, service provided).</p></li><li><p><strong>Note:</strong> Optional field for additional remarks.</p></li></ul><h2>Benefits</h2><p> Provides a <strong>complete history of customer transactions</strong>.<br> Helps track <strong>payments received and pending balances</strong>.<br> Supports <strong>credit management</strong> by showing overdue amounts.<br> Useful for <strong>auditing and reporting</strong> customer accounts.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T11:02:50.2489604' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'27dea0cc-60bf-480d-8dcc-248b081e429f', N'TRANSACTIONS', N'Transactions', N'<p>A <strong>Transaction</strong> is any financial activity that takes place in your business.<br>It could be a <strong>sale, purchase, payment, salary expense, opening balance, or year-end closing entry</strong>.</p><p>Every transaction is recorded with details like the date, type, amount, payment status, and store location. This helps you keep track of money coming <strong>in</strong> (income) and going <strong>out</strong> (expenses).</p><hr><h2>Why Transactions are Important</h2><ul><li><p>They give you a <strong>complete financial history</strong> of your business.</p></li><li><p>You can easily see which payments are <strong>pending, partial, or completed</strong>.</p></li><li><p>Transactions make it simple to generate <strong>reports, profit/loss statements, and tax filings</strong>.</p></li><li><p>They act as an <strong>audit trail</strong>, showing every financial activity in detail.</p></li></ul><hr><h2>Key Details in a Transaction</h2><ul><li><p><strong>Transaction Date</strong> → When it happened.</p></li><li><p><strong>Transaction Number</strong> → A unique ID (auto-generated).</p></li><li><p><strong>Reference Number</strong> → Related order or invoice number.</p></li><li><p><strong>Transaction Type</strong> → Sale, Purchase, Payroll, Opening Balance, Year Closing, etc.</p></li><li><p><strong>Status</strong> → Pending or Completed.</p></li><li><p><strong>Balance Amount</strong> → Amount still unpaid.</p></li><li><p><strong>Paid Amount</strong> → Amount already paid.</p></li><li><p><strong>Payment Status</strong> → Pending, Partial, or Completed.</p></li><li><p><strong>Sub Total</strong> → Amount before tax.</p></li><li><p><strong>Tax</strong> → Applicable tax.</p></li><li><p><strong>Total</strong> → Final payable/receivable amount.</p></li><li><p><strong>Store/Location</strong> → Where the transaction was made.</p></li></ul><hr><h2>Examples of Transactions</h2><ul><li><p><strong>Purchase</strong> → Buying goods for your store.</p></li><li><p><strong>Sale</strong> → Selling goods to customers.</p></li><li><p><strong>Payroll</strong> → Recording employee salaries.</p></li><li><p><strong>Opening Balance</strong> → Setting up balances at the start of the year.</p></li><li><p><strong>Year-End Closing</strong> → Closing books and carrying forward net profit/loss.</p></li></ul><hr><h2>Example Entry</h2><ul><li><p><strong>Date:</strong> 9/12/2025 6:38:43 PM</p></li><li><p><strong>Transaction Number:</strong> SAL-20250912-0001</p></li><li><p><strong>Type:</strong> Sale</p></li><li><p><strong>Status:</strong> Completed</p></li><li><p><strong>Balance Amount:</strong> $1,<a href="400.00" target="_blank">400.00</a></p></li><li><p><strong>Paid Amount:</strong> $<a href="100.00" target="_blank">100.00</a></p></li><li><p><strong>Payment Status:</strong> Partial</p></li><li><p><strong>Total:</strong> $1,<a href="500.00" target="_blank">500.00</a></p></li><li><p><strong>Store:</strong> Park City Shop</p></li></ul>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:36:43.0244995' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'c5f3316e-ca08-4821-a08e-2acd1f6054de', N'LEDGER_ACCOUNTS', N'Ledger Accounts', N'<p>asily manage your company’s financial transactions with well-organized <strong>Ledger Accounts</strong>, ensuring accurate bookkeeping, reporting, and compliance.</p><hr><h2>Key Ledger Account Attributes</h2><h3><strong>Account Code</strong></h3><p>A unique identifier for each ledger account.<br><strong>Example:</strong> <code>4100</code></p><h3><strong>Account Name</strong></h3><p>The descriptive name of the ledger account.<br><strong>Example:</strong> <code>Sales Revenue</code></p><h3><strong>Account Type</strong></h3><p>Specifies the category of the account for financial reporting.</p><ul><li><p>Asset</p></li><li><p>Liability</p></li><li><p>Equity</p></li><li><p>Income</p></li><li><p>Expense<br><strong>Example:</strong> <code>Expense</code></p></li></ul><h3><strong>Account Group</strong></h3><p>Groups accounts under sub-classifications for better financial clarity.<br><strong>Example:</strong> <code>Indirect Expense</code></p><h3><strong>Opening Balance</strong></h3><p>The initial balance when the account is created or when books are opened.<br><strong>Example:</strong> <code>$</code><a href="0.00" target="_blank"><code>0.00</code></a></p><h3><strong>Is Active</strong></h3><p>Indicates whether the account is currently active and available for use.<br><strong>Example:</strong> <code>Active</code></p><hr><h2>Ledger Accounts by Type</h2><h3> <strong>Equity Accounts (Capital &amp; Reserves)</strong></h3><ul><li><p><strong>5555 – Opening Balance</strong> → Records opening balance during initial setup.</p></li><li><p><strong>3200 – Retained Earnings</strong> → Holds accumulated profits retained in the business.</p></li><li><p><strong>3100 – Income Summary</strong> → Temporary account to close income and expenses.</p></li></ul><hr><h3> <strong>Asset Accounts (Resources Owned)</strong></h3><ul><li><p><strong>1200 – Inventory</strong> → Tracks the value of stock on hand.</p></li><li><p><strong>1154 – Input - Excise Tax</strong> → Records excise tax paid on purchases.</p></li></ul><hr><h3> <strong>Liability Accounts (Obligations)</strong></h3><ul><li><p><strong>2100 – Accounts Payable</strong> → Records amounts due to suppliers.</p></li><li><p><strong>2200 – Salary Payable</strong> → Salaries owed but not yet paid.</p></li><li><p><strong>2150 – Output</strong> → Tracks general sales tax collected.</p></li><li><p><strong>2151 – Output - Sales Tax</strong> → Records sales tax liability.</p></li><li><p><strong>2152 – Output - SGST</strong> → State-level GST liability.</p></li><li><p><strong>2153 – Output - CGST</strong> → Central GST liability.</p></li><li><p><strong>2154 – Output - Excise Tax</strong> → Excise tax collected on sales.</p></li></ul><hr><h3><strong>Income Accounts (Revenue &amp; Gains)</strong></h3><ul><li><p><strong>4100 – Sales Revenue</strong> → Income from goods/services sold.</p></li><li><p><strong>4150 – Sales Return</strong> → Records value of returned goods.</p></li><li><p><strong>4200 – Discount Received</strong> → Discounts earned from suppliers.</p></li><li><p><strong>5401 – Stock Adjustment (Gain)</strong> → Gains from stock adjustments.</p></li></ul><hr><h3><strong>Expense Accounts (Costs &amp; Losses)</strong></h3><ul><li><p><strong>5100 – Cost of Goods Sold</strong> → Direct costs of goods sold.</p></li><li><p><strong>5200 – Discount Given</strong> → Discounts offered to customers.</p></li><li><p><strong>5300 – General Expense</strong> → Miscellaneous operating expenses.</p></li><li><p><strong>5400 – Stock Adjustment (Loss)</strong> → Loss from stock adjustments.</p></li><li><p><strong>5900 – Round Off</strong> → Adjustments due to rounding differences.</p></li><li><p><strong>6100 – Salary Expense</strong> → Regular staff salary payments.</p></li><li><p><strong>6110 – Bonus Expense</strong> → Extra payments/bonuses for employees.</p></li><li><p><strong>6120 – Commission Expense</strong> → Commissions paid.</p></li><li><p><strong>6130 – Festival Bonus Expense</strong> → Special festival-related employee bonuses.</p></li><li><p><strong>6140 – Travel Allowance Expense</strong> → Travel reimbursements/allowances.</p></li><li><p><strong>6150 – Mobile Bill Expense</strong> → Telecom/mobile expenses.</p></li><li><p><strong>6160 – Food Bill Expense</strong> → Meal/food expenses.</p></li><li><p><strong>6170 – Advance Salary Expense</strong> → Salary given in advance.</p></li><li><p><strong>6190 – Other Staff Expense</strong> → Other miscellaneous staff-related expenses.</p></li></ul><hr><h2>Benefits of Ledger Management</h2><p> Clear categorization of financial data.<br> Improved accuracy in <strong>reporting &amp; compliance</strong>.<br> Easy tracking of <strong>assets, liabilities, income, and expenses</strong>.<br> Supports <strong>decision-making</strong> with organized financial records.<br> Enables <strong>alerts &amp; controls</strong> through opening balances and account activity.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:15:29.1149042' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'2d0cf879-3c68-4986-8f1a-442a511b9acc', N'TRIAL_BALANCE_REPORT', N'Trial Balance Report', N'<p>The <strong>Trial Balance Report</strong> provides a summary of all ledger accounts’ <strong>debit and credit balances</strong> for a selected <strong>store/location</strong> and <strong>date range</strong>.<br>It is used to <strong>verify that total debits equal total credits</strong>, ensuring that your books are mathematically balanced before preparing financial statements.</p><hr><h2>Report Filters</h2><p>You can filter the trial balance using:</p><ul><li><p><strong>Created Date / Date Range:</strong> View balances for a specific period (e.g., 9/1/2025 – 9/13/2025).</p></li><li><p><strong>Store/Location:</strong> Choose the branch or shop to view its accounts (e.g., <em>Park City Shop</em>).</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Account Name:</strong> Name of the ledger account (e.g., <em>Cash, Salary Expense, Sales Revenue</em>).</p></li><li><p><strong>Debit Amount:</strong> Total debits recorded in that account during the selected period.</p></li><li><p><strong>Credit Amount:</strong> Total credits recorded in that account during the selected period.</p></li></ul><h2>Key Points</h2><ul><li><p><strong>Debits = Credits:</strong> The total of all debit balances must equal the total of all credit balances.</p></li><li><p><strong>Verification Tool:</strong> Ensures that all journal entries are correctly posted.</p></li><li><p><strong>Supports Financial Reports:</strong> Forms the basis for <strong>Profit &amp; Loss</strong> and <strong>Balance Sheet</strong> preparation.</p></li></ul><hr><h2>Benefits</h2><p> Quickly check account accuracy before finalizing financial statements.<br> Detect posting errors or missing transactions.<br> Provides a <strong>complete snapshot of account balances</strong> at any point in time.<br> Helps accountants and business owners maintain <strong>balanced books</strong>.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:53:21.2347402' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'fd7726a8-92a4-4fb7-bfad-4a5e0588b426', N'CASH_FLOW_REPORT', N'Cash Flow Report', N'<p>The <strong>Cash Flow Report</strong> provides a summary of <strong>cash inflows and outflows</strong> for a selected <strong>store/location</strong> and <strong>date range</strong>.<br>It helps business owners monitor liquidity, manage cash effectively, and plan for expenses.</p><hr><h2>Report Filters</h2><ul><li><p><strong>Created Date / Date Range:</strong> View cash flow for a specific period (e.g., 9/1/2025 – 9/13/2025).</p></li><li><p><strong>Store/Location:</strong> Choose the branch or shop (e.g., <em>Park City Shop</em>).</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Account Name:</strong> Name of the account involved in cash movement (e.g., <em>Cash, Salary Payable, Accounts Receivable</em>).</p></li><li><p><strong>Cash Received:</strong> Total cash inflows for that account during the selected period.</p></li><li><p><strong>Cash Paid:</strong> Total cash outflows for that account during the selected period.</p></li></ul><h2>Key Points</h2><ul><li><p><strong>Cash Inflows (Received):</strong> Money coming into the business, such as customer payments or opening balance.</p></li><li><p><strong>Cash Outflows (Paid):</strong> Money leaving the business, such as salaries, payments to vendors, or expenses.</p></li><li><p><strong>Net Cash Flow:</strong> Difference between cash received and cash paid, indicating whether cash increased or decreased.</p></li></ul><hr><h2>Benefits</h2><p> Provides a <strong>clear view of cash movements</strong> for the business.<br> Helps in <strong>managing liquidity</strong> and planning future payments.<br> Supports decision-making for <strong>investments, purchases, and payroll</strong>.<br> Ensures <strong>accurate cash tracking</strong> for accounting and auditing purposes.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:54:56.0062583' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'60474c59-a1d2-4ae1-8fd4-4c217c4f4ee2', N'PAY_ROLL_LIST', N'Pay Rolls', N'<p>The <strong>Payroll List</strong> provides a detailed overview of salary payments for employees in a selected <strong>store/location</strong> and <strong>salary month</strong>.<br>It helps HR and accounting staff manage payroll, track payments, and ensure employees are paid accurately.</p><hr><h2>Report Filters</h2><ul><li><p><strong>Salary Date:</strong> View payroll records for a specific payment date.</p></li><li><p><strong>Employee:</strong> Filter by a specific employee to see individual salary details.</p></li><li><p><strong>Store/Location:</strong> Select the branch or shop (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Salary Month:</strong> Filter salaries by the relevant month.</p></li><li><p><strong>Payment Mode:</strong> Filter by mode of payment (e.g., Cash, Bank Transfer, Cheque).</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Salary Date:</strong> Date when the salary was paid.</p></li><li><p><strong>Employee:</strong> Name of the employee receiving the salary.</p></li><li><p><strong>Store/Location:</strong> Branch or shop of the employee.</p></li><li><p><strong>Salary Month:</strong> Month for which the salary is paid.</p></li><li><p><strong>Payment Mode:</strong> Method used to pay the employee (Cash, Bank, Cheque, etc.).</p></li><li><p><strong>Basic Salary:</strong> Fixed salary component for the employee.</p></li><li><p><strong>Total Salary:</strong> Full salary including allowances, bonuses, and deductions.</p></li></ul><h2>Benefits</h2><p> Provides a <strong>complete view of all salary payments</strong>.<br> Helps in <strong>tracking payroll by employee, month, or branch</strong>.<br> Ensures <strong>accurate payment and compliance</strong> with company policies.<br> Useful for <strong>audits, reports, and financial planning</strong>.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:58:34.1876324' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'f4e7f6d8-63d0-46ea-b0d6-4da862df4c20', N'GENERAL_ENTRY_REPORT', N'General Entry Report', N'<p>The <strong>General Entry Report</strong> provides a detailed list of all journal entries recorded in the system for a selected <strong>store/location</strong> and <strong>financial year</strong>.<br>It is mainly used to track <strong>debits and credits</strong> across accounts, ensuring that every financial transaction is properly balanced.</p><hr><h2>Report Purpose</h2><ul><li><p>Maintain a <strong>complete audit trail</strong> of financial transactions.</p></li><li><p>Show which accounts were affected by each entry.</p></li><li><p>Help accountants and business owners <strong>verify accuracy</strong> and prepare financial statements.</p></li></ul><hr><h2>Report Filters</h2><p>You can filter the list of entries before viewing/exporting:</p><ul><li><p><strong>Transaction Number</strong>: Search by a unique journal entry ID (e.g., <em>OBL-20250913-0001</em>).</p></li><li><p><strong>Created Date</strong>: Select a specific date when the transaction was recorded.</p></li><li><p><strong>From Date / To Date</strong>: View entries within a date range.</p></li><li><p><strong>Store/Location</strong>: Choose the branch or shop (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Financial Year</strong>: Select the accounting year for which entries should be displayed.</p></li></ul><hr><h2>Report Fields</h2><p>Each row in the report displays the details of a transaction:</p><ul><li><p><strong>Created Date</strong> – When the entry was made.</p></li><li><p><strong>Transaction Number</strong> – Unique identifier of the entry.</p></li><li><p><strong>Account Code &amp; Account Name</strong> – Ledger account affected.</p></li><li><p><strong>Debit Amount</strong> – Amount recorded as debit (increases assets/expenses).</p></li><li><p><strong>Credit Amount</strong> – Amount recorded as credit (increases liabilities/equity/income).</p></li><li><p><strong>Account Type</strong> – Classification of the account (Asset, Liability, Equity, Income, Expense).</p></li></ul><h2>Benefits</h2><p> Ensures <strong>accuracy and balance</strong> in accounts.<br> Provides <strong>transparent tracking</strong> of every debit/credit entry.<br> Helps prepare <strong>Profit &amp; Loss</strong> and <strong>Balance Sheet</strong> reports.<br> Acts as an <strong>audit trail</strong> for compliance and reviews.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:51:18.0771351' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'355fed21-25a6-4dd6-a645-4db39607557e', N'TAX_REPORT', N'Tax Report', N'<p>The <strong>Tax Report</strong> provides a summary of all tax-related transactions for a selected <strong>store/location</strong> and <strong>financial year</strong>.<br>It helps businesses track taxes on purchases and sales and calculate the <strong>net tax payable or receivable</strong>.</p><hr><h2>Report Fields</h2><ul><li><p><strong>Store/Location:</strong> The branch or outlet the report belongs to (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Financial Year:</strong> The accounting year selected for the report.</p></li></ul><h3>Tax Details</h3><ul><li><p><strong>Input Tax Total:</strong> Total tax paid on purchases.</p></li><li><p><strong>Input Tax Return Total:</strong> Tax refunds/returns claimed on purchases.</p></li><li><p><strong>Output Tax Total:</strong> Total tax collected from sales.</p></li><li><p><strong>Output Tax Return Total:</strong> Tax refunds/returns on sales.</p></li><li><p><strong>Net Tax Payable:</strong> Final tax amount to be paid = <em>(Output Tax – Input Tax)</em> after adjustments.</p></li></ul><h3>Status</h3><p>Shows whether the tax report is:</p><ul><li><p><strong>Pending</strong> – Yet to be filed/verified.</p></li><li><p><strong>Submitted</strong> – Tax report has been filed.</p></li><li><p><strong>Paid</strong> – Tax payment has been cleared.</p></li><li><p><strong>Refundable</strong> – Business is eligible for a refund (if Input Tax &gt; Output Tax).</p></li></ul><hr><h2>Benefits of the Tax Report</h2><p> Simplifies tax compliance.<br> Tracks input vs. output taxes clearly.<br> Helps avoid overpayment or missed refunds.<br> Provides proof for audits and filings.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:40:59.8505646' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'80b71365-b7d6-4dfe-9bd2-8bbfc58e26a2', N'TRANSACTION_ITEMS', N'Customer Pending Payment Sales Order Item', N'<p>This report provides a <strong>detailed view of individual sales orders</strong> that have pending payments for customers.<br>It helps businesses <strong>track outstanding payments at the order level</strong> and follow up efficiently.</p><hr><h2>Report Filters</h2><ul><li><p><strong>Order Date / Date Range:</strong> View sales orders within a specific period.</p></li><li><p><strong>Customer:</strong> Filter by a specific customer to see only their pending orders.</p></li><li><p><strong>Payment Status:</strong> Filter orders by payment status (e.g., <em>Pending</em>, <em>Partial</em>, <em>Paid</em>).</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Order Date:</strong> The date when the sales order was created.</p></li><li><p><strong>Order Number:</strong> Unique identifier of the sales order.</p></li><li><p><strong>Total:</strong> Total amount of the order.</p></li><li><p><strong>Total Tax:</strong> Tax applied to the order.</p></li><li><p><strong>Total Discount:</strong> Any discount given on the order.</p></li><li><p><strong>Total Paid:</strong> Amount already received from the customer.</p></li><li><p><strong>Remaining Amount:</strong> Outstanding amount that is yet to be paid.</p></li><li><p><strong>Payment Status:</strong> Status of the payment (e.g., <em>Pending</em>, <em>Partial</em>, <em>Paid</em>).</p></li></ul><h2>Benefits</h2><p> Provides <strong>detailed tracking of unpaid sales orders</strong>.<br> Helps identify which orders require <strong>follow-up for payment collection</strong>.<br> Supports <strong>cash flow management</strong> by showing remaining receivables.<br> Enables <strong>accurate reporting and auditing</strong> of pending customer payments.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T11:12:35.9009675' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'87847201-93fe-4226-bca4-b61311fc3cd5', N'FINANCIAL_YEAR', N'Financial Years', N'<p>The <strong>Financial Year</strong> defines the accounting period used for recording transactions, generating reports, and closing books.</p><hr><h2>Key Attributes</h2><p><strong>Start Date</strong><br>The date when the financial year begins.</p><ul><li><p>Editable</p></li><li><p>Example: <code>01-Apr-2025</code></p></li></ul><p><strong>End Date</strong><br>The date when the financial year ends.</p><ul><li><p>Editable</p></li><li><p>Example: <code>31-Mar-2026</code></p></li></ul><p><strong>Closed</strong><br>Shows whether the financial year is finalized.</p><ul><li><p>Yes → No new entries allowed</p></li><li><p>No → Still open for posting transactions</p></li></ul><p><strong>Close Date</strong><br>The date when the financial year was actually closed.</p><ul><li><p>Automatically recorded once closed</p></li><li><p>Example: <code>15-Apr-2026</code></p></li></ul><hr><h2>Allowed Actions</h2><ul><li><p>Edit <strong>Start Date</strong></p></li><li><p>Edit <strong>End Date</strong></p></li><li><p>Creation of new financial years is not permitted</p></li></ul><hr><h2>Benefits</h2><ul><li><p>Keeps accounting periods consistent</p></li><li><p>Avoids duplicate financial years</p></li><li><p>Provides better control over reporting timelines</p></li></ul>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:20:02.8084427' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'e67bf091-3aab-46dc-add1-beb5f6dc2cc3', N'MANAGE_CUSTOMER_LADGER', N'Manage Customer Ladger', N'<p>The <strong>Manage Customer Ledger</strong> feature allows you to record or update transactions for a customer, keeping track of payments, balances, and overdue amounts.<br>It helps maintain accurate customer accounts and ensures proper accounting of receivables.</p><hr><h2>Form Fields</h2><ul><li><p><strong>Date *</strong>: The date of the transaction (e.g., <em>9/13/2025</em>).</p></li><li><p><strong>Store/Location *</strong>: Select the branch or shop where the transaction occurred (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Customer *</strong>: Select the customer for whom the transaction is recorded.</p></li><li><p><strong>Overdue</strong>: Displays the customer’s pending overdue amount.</p></li><li><p><strong>Balance</strong>: Shows the customer’s current balance after the transaction.</p></li><li><p><strong>Amount *</strong>: Enter the transaction amount (payment received or invoice amount).</p></li><li><p><strong>Reference</strong>: Optional field for entering transaction reference numbers (e.g., invoice or receipt ID).</p></li><li><p><strong>Description</strong>: Brief details about the transaction (e.g., product sold, service provided).</p></li><li><p><strong>Note</strong>: Optional field for additional remarks or comments.</p></li></ul><hr><h2>Benefits</h2><p> Helps maintain <strong>accurate customer account records</strong>.<br> Tracks <strong>payments, balances, and overdue amounts</strong> efficiently.<br> Supports <strong>audit and reporting</strong> for customer transactions.<br> Ensures proper accounting of receivables for better cash flow management.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T11:07:31.7143647' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'4702fb88-67ad-4006-910b-c7e9576cb27f', N'CUSTOMER_PENING_SALES_ORDER', N'Customer Pending Payment', N'<p>The <strong>Customer Pending Payment</strong> report shows all customers who have <strong>outstanding payments</strong>.<br>It helps businesses track receivables and follow up on pending amounts to maintain healthy cash flow.</p><hr><h2>Report Filters</h2><ul><li><p><strong>Customer:</strong> Filter by a specific customer to view only their pending payments.</p></li><li><p><strong>Payment Status:</strong> Filter by status such as <em>Pending</em> or <em>Paid</em>.</p></li></ul><hr><h2>Report Fields</h2><ul><li><p><strong>Customer Name:</strong> Name of the customer with pending payments.</p></li><li><p><strong>Total Pending:</strong> Total amount that the customer has yet to pay.</p></li><li><p><strong>Payment Status:</strong> Current status of the payment (e.g., <em>Pending</em> or <em>Paid</em>).</p></li></ul><h2>Benefits</h2><p> Quickly identifies <strong>customers with unpaid balances</strong>.<br> Helps prioritize follow-ups and collection efforts.<br> Supports <strong>cash flow management</strong> by highlighting pending receivables.<br> Provides a <strong>snapshot of customer payment status</strong> for reporting and auditing.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T11:11:09.0638536' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'33120259-a5ef-4d61-8469-f05dffc482c7', N'ACCOUNT_BALANCE_REPORT', N'Account Balance Report', N'<p>The <strong>Account Balance Report</strong> provides a detailed view of debit and credit transactions for each account within a selected <strong>store/location</strong> and <strong>financial year</strong>.<br>It helps track how money flows through different accounts and ensures proper reconciliation.</p><hr><h2>Report Fields</h2><ul><li><p><strong>Store/Location:</strong> The shop or branch the report belongs to (e.g., <em>Park City Shop</em>).</p></li><li><p><strong>Financial Year:</strong> The accounting year for which the report is generated (e.g., <em>04/01/2024 – 03/31/2025</em>).</p></li></ul><h3>Account-Wise Balances</h3><ul><li><p><strong>Account Name:</strong> The specific account (e.g., <em>Salary Payable, Salary Expense, Cash</em>).</p></li><li><p><strong>Debit Total:</strong> Total debits posted to that account during the selected period.</p></li><li><p><strong>Credit Total:</strong> Total credits posted to that account during the selected period.</p></li></ul><h2>Benefits of the Account Balance Report</h2><p> Provides transparency on debit and credit movements.<br> Helps reconcile accounts at the end of the financial year.<br> Supports accurate financial statements like Profit &amp; Loss and Balance Sheet.<br> Useful for auditing and error detection.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:47:43.4300181' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'273fb6c8-423e-45d4-907f-f9d367844bc0', N'MANAGE_FINANCIAL_YEAR', N'Manage Financial Year', N'<p>The <strong>Financial Year</strong> defines the accounting period for recording and reporting transactions.<br>In this module, you can only <strong>update the Start Date and End Date</strong> of the existing financial year.</p><hr><h2>Fields</h2><p>**Start Date ***</p><ul><li><p>The date when the financial year begins.</p></li><li><p>Mandatory field.</p></li><li><p>Example: <code>01/01/2026</code></p></li></ul><p>**End Date ***</p><ul><li><p>The date when the financial year ends.</p></li><li><p>Mandatory field.</p></li><li><p>Example: <code>31/12/2026</code></p></li></ul><hr><h2>Rules</h2><ul><li><p>Only <strong>Start Date</strong> and <strong>End Date</strong> can be modified.</p></li><li><p>Both fields are required to save changes.</p></li></ul><hr><h2>Benefits</h2><ul><li><p>Maintains a consistent accounting period.</p></li><li><p>Ensures accurate reporting across the system.</p></li></ul>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:31:53.2887036' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'f31b6f4b-8d37-4cd1-b9eb-8642ff55c4f1', N'LOAN', N'Loan Management', N'<p>The <strong>Loan module</strong> allows businesses to record, track, and manage loans taken from lenders or financial institutions. It provides a clear breakdown of loan amounts, repayments, and outstanding balances.</p><hr><h2>Report Fields / Columns</h2><ul><li><p><strong>Action:</strong> Options to edit, view details, or delete a loan record.</p></li><li><p><strong>Account Name:</strong> The account under which the loan is recorded (e.g., <em>Bank Loan</em>, <em>Personal Loan</em>).</p></li><li><p><strong>Loan Date:</strong> The date the loan was issued or recorded.</p></li><li><p><strong>Loan Amount:</strong> The total principal amount borrowed.</p></li><li><p><strong>Total Paid Principal:</strong> The total portion of the loan’s principal that has already been repaid.</p></li><li><p><strong>Total Paid Interest:</strong> The total interest paid to date on the loan.</p></li><li><p><strong>Lender Name:</strong> The name of the person, bank, or financial institution providing the loan.</p></li><li><p><strong>Branch:</strong> The branch or location of the lender (e.g., <em>City Bank – Park City Branch</em>).</p></li></ul><h2>Benefits</h2><p> Provides <strong>clear visibility of loan amounts, repayments, and balances</strong>.<br> Helps monitor <strong>principal vs. interest payments</strong> separately.<br> Ensures accurate <strong>financial reporting</strong> of liabilities.<br> Keeps track of <strong>multiple lenders and branches</strong> in one place.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-19T04:39:26.6688244' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'2902f7d0-dd6b-4ecf-96bf-d9ba11648d02', N'MANAGE_LOAN', N'Manage Loan', N'<p>The <strong>Manage Loan</strong> form allows users to record and maintain details of loans taken from banks, lenders, or financial institutions. This ensures proper tracking of borrowed funds, repayments, and lender information.</p><hr><h2>Form Fields</h2><ul><li><p><strong>Branch *</strong><br>Select the store or location where the loan is recorded.<br><em>Example:</em> <em>Park City Shop</em></p></li><li><p><strong>Loan Amount *</strong><br>Enter the total principal amount of the loan.<br><em>Example:</em> <em>$50,</em><a href="000.00" target="_blank"><em>000.00</em></a></p></li><li><p><strong>Lender Name *</strong><br>Provide the name of the bank, institution, or individual lender.<br><em>Example:</em> <em>City Bank</em></p></li><li><p><strong>Loan Date *</strong><br>Select the date when the loan was taken.<br><em>Example:</em> <em>9/13/2025</em></p></li><li><p><strong>Narration (Optional)</strong><br>Add any notes or descriptions related to the loan.<br><em>Example:</em> <em>Loan taken for shop expansion project.</em></p></li></ul><h2>Benefits</h2><p> Keeps all loan details organized in one place.<br> Provides clarity on the lender and branch associated with the loan.<br> Ensures financial accountability by recording loan amounts and dates.<br> Supports reporting for liabilities and cash flow planning.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-19T04:40:23.0221982' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'655174ba-7e9a-40f3-aa3e-6bf0a6eab143', N'MANAGE_OPENING_BALANCE', N'Manage Opening Balance', N'<p>The <strong>Manage Opening Balance</strong> form is used to enter the initial balances of accounts at the start of a <strong>financial year</strong>. This ensures accurate tracking of assets, liabilities, equity, and other accounts right from the beginning.</p><hr><h2>Form Fields</h2><ul><li><p><strong>Financial Year</strong><br>Displays the active financial year in which the opening balance is being set.<br><em>Example:</em> <em>1/1/2025 – 12/31/2026</em></p></li><li><p><strong>Location *</strong><br>Select the store or branch for which the opening balance is being recorded.<br><em>Example:</em> <em>Park City Shop</em></p></li><li><p><strong>Account *</strong><br>Choose the account for which the opening balance will be set.<br><em>Example:</em> <em>Cash, Accounts Receivable, Salary Payable</em></p></li><li><p><strong>Opening Balance *</strong><br>Enter the initial balance amount of the selected account.<br><em>Example:</em> <em>$10,</em><a href="000.00" target="_blank"><em>000.00</em></a></p></li><li><p><strong>Type *</strong><br>Specify whether the opening balance is a <strong>Debit</strong> or <strong>Credit</strong> balance.<br><em>Example:</em></p><ul><li><p>Debit → <em>Assets, Expenses</em></p></li><li><p>Credit → <em>Liabilities, Income, Equity</em></p></li></ul></li></ul><hr><h2>Example Form Layout</h2><p><strong>Manage Opening Balance</strong></p><ul><li><p>Financial Year: 1/1/2025 – 12/31/2026</p></li><li><p>Location: Park City Shop</p></li><li><p>Account: Cash</p></li><li><p>Opening Balance: $10,<a href="000.00" target="_blank">000.00</a></p></li><li><p>Type: Debit</p></li></ul><hr><h2>Benefits</h2><p> Ensures <strong>accurate account balances</strong> at the start of a financial year.<br> Helps maintain <strong>proper accounting records</strong> across multiple stores/locations.<br> Separates <strong>debit and credit types</strong> for correct financial reporting.<br> Forms the basis for <strong>Trial Balance, Balance Sheet, and Profit &amp; Loss</strong> accuracy.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-19T04:41:17.6763177' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'f5cfafc8-2b78-47c0-8280-7b4d59aabb86', N'MANAGE_LOAN_PAYMENT', N'Manage Loan Payment', N'<p>The <strong>Manage Loan Payment</strong> form is used to record repayments made towards an existing loan. Payments are split into <strong>principal</strong> and <strong>interest</strong> amounts, ensuring accurate financial tracking of liabilities and expenses.</p><hr><h2>Form Fields</h2><ul><li><p><strong>Account Name *</strong><br>Select the loan account against which the payment is being recorded.<br><em>Example:</em> <em>Loan Payable – Meet</em></p></li><li><p><strong>Principal Amount</strong><br>Enter the portion of the repayment that reduces the loan’s principal balance.<br><em>Example:</em> <em>$</em><a href="500.00" target="_blank"><em>500.00</em></a></p></li><li><p><strong>Interest Amount</strong><br>Enter the portion of the repayment that goes toward interest expense.<br><em>Example:</em> <em>$</em><a href="50.00" target="_blank"><em>50.00</em></a></p></li><li><p><strong>Payment Date *</strong><br>Select the date on which the payment was made.<br><em>Example:</em> <em>9/20/2025</em></p></li><li><p><strong>Notes (Optional)</strong><br>Add remarks or details about the payment.<br><em>Example:</em> <em>Monthly EMI for September.</em></p></li></ul><h2>Benefits</h2><p> Keeps clear records of each loan repayment.<br> Splits <strong>principal vs. interest</strong>, ensuring correct accounting treatment.<br> Helps track <strong>outstanding loan balances</strong> over time.<br> Provides a transparent payment history for auditing and reporting.</p>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-20T11:28:31.3720320' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'15b0600a-f840-4088-aada-3f9d8f6deda5', N'ADD_GENERAL_ENTRY',N'Add General Entry',N'<p>The <strong>Add General Entry</strong> form allows users to manually record accounting transactions directly into the ledger. It is used to ensure that every financial transaction is properly captured, with debits and credits balanced across accounts.</p><hr><h2>Form Purpose</h2><ul><li>Record manual accounting entries that do not involve automated invoices or payments.</li><li>Ensure proper ledger updates for assets, liabilities, equity, income, and expense accounts.</li><li>Maintain a complete and auditable trail of financial activity.</li></ul><h2>Form Fields</h2><ul><li><strong>Store / Location *</strong><br>Select the branch or location where the transaction occurs.<br><em>Example:</em> Park City Shop</li><li><strong>Date *</strong><br>Select the transaction date.<br><em>Example:</em> 10/4/2025</li><li><strong>Amount *</strong><br>Total value of the transaction.<br><em>Example:</em> 1000.00</li><li><strong>Reference Number *</strong><br>Unique identifier for the transaction.<br><em>Example:</em> GEN-20251004-0001</li><li><strong>Debit Account *</strong><br>Select the account to be debited.<br><em>Example:</em> Cash</li><li><strong>Credit Account *</strong><br>Select the account to be credited.<br><em>Example:</em> Sales</li><li><strong>Narration *</strong><br>Enter a description or purpose for the transaction.<br><em>Example:</em> Customer payment received for September</li></ul><h2>Benefits</h2><ul><li>Ensures that all manual accounting transactions are accurately recorded and balanced.</li><li>Maintains proper ledger integrity across debit and credit accounts.</li><li>Provides transparency and traceability for auditing purposes.</li><li>Helps accountants and business owners track financial activity for reporting.</li></ul>', CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:31:53.2887036' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0);
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'52907ab8-fd63-490b-98eb-7d50bafc3381', N'PAYMENT_REPORT',N'Payment Entry List',N'<p>The <strong>Payment Entry List</strong> displays all payments recorded in the system for each transaction, such as sales orders, invoices, or other receivables.</p><hr><h2>Purpose</h2><ul><li>Show all payment transactions per branch/location.</li><li>Provide a clear audit trail of amounts received.</li><li>Ensure that total payments match the associated transaction amounts.</li></ul><h2>Filters</h2><ul><li><strong>Transaction Number:</strong> Search by unique transaction ID.</li><li><strong>From Date / To Date:</strong> View payments within a date range.</li><li><strong>Store / Location:</strong> Filter payments by branch or shop.</li><li><strong>Payment Method:</strong> Filter by cash, card, or other methods.</li></ul><h2>Fields Displayed</h2><ul><li><strong>Payment Date</strong> – When the payment was made.</li><li><strong>Transaction Number</strong> – Associated transaction.</li><li><strong>Amount</strong> – Payment amount received.</li><li><strong>Payment Method</strong> – Cash, Bank, Card, etc.</li><li><strong>Reference Number</strong> – Payment reference.</li><li><strong>Narration</strong> – Optional notes describing the payment.</li><li><strong>Status</strong> – Completed or pending.</li></ul><h2>Benefits</h2><ul><li>Provides transparency of payments for each transaction.</li><li>Helps accountants verify totals and reconcile payments.</li><li>Acts as an audit trail for financial compliance and reporting.</li></ul>',CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:31:53.2887036' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'eed7fd44-f772-4ab5-9d03-0963440ed086', N'DAILY_REPORT_SUMMARY',N'Today''s Summary Report',N'<p>The <strong>Today''s Summary Report</strong> provides a detailed overview of all sales, purchases, and payment activities for a selected store/location on the current day. It helps track financial performance, verify transactions, and ensure audit compliance.</p><hr><h2>Sales Summary</h2><ul><li><strong>Transaction Count</strong> – Total number of sales transactions recorded today.<br><em>Example:</em> 15 transactions</li><li><strong>Gross Sales</strong> – Σ (Item Selling Price × Quantity).<br><em>Example:</em> 10 items × $50 = $500</li><li><strong>Discounts</strong> – Trade or promotional discounts applied.<br><em>Example:</em> $50 off total sales</li><li><strong>Taxable Amount</strong> – Gross Sales – Discounts.<br><em>Example:</em> $500 - $50 = $450</li><li><strong>Tax</strong> – Taxable Amount × Tax Rate.<br><em>Example:</em> $450 × 10% = $45</li><li><strong>Net Sales</strong> – Taxable Amount + Tax.<br><em>Example:</em> $450 + $45 = $495</li><li><strong>Items Sold Count</strong> – Total quantity of items sold.<br><em>Example:</em> 10 items</li><li><strong>Items Returned</strong> – Count of returned items.<br><em>Example:</em> 1 returned item</li><li><strong>Average Sale</strong> – Net Sales ÷ Transaction Count.<br><em>Example:</em> $495 ÷ 15 = $33 per transaction</li></ul><h2>Purchase Summary</h2><ul><li><strong>Transaction Count</strong> – Total number of purchase transactions recorded today.</li><li><strong>Gross Purchase</strong> – Σ (Item Purchase Price × Quantity).<br><em>Example:</em> 20 items × $30 = $600</li><li><strong>Discounts</strong> – Trade or promotional discounts applied.<br><em>Example:</em> $60 discount</li><li><strong>Taxable Amount</strong> – Gross Purchase – Discounts.<br><em>Example:</em> $600 - $60 = $540</li><li><strong>Tax</strong> – Taxable Amount × Tax Rate.<br><em>Example:</em> $540 × 10% = $54</li><li><strong>Net Purchase</strong> – Taxable Amount + Tax.<br><em>Example:</em> $540 + $54 = $594</li><li><strong>Purchased Items Count</strong> – Total number of items purchased.<br><em>Example:</em> 20 items</li><li><strong>Items Returned</strong> – Count of items returned.<br><em>Example:</em> 2 items</li><li><strong>Average Purchase</strong> – Net Purchase ÷ Transaction Count.<br><em>Example:</em> $594 ÷ 5 = $118 per transaction</li></ul><h2>Payment Breakdown</h2><ul><li><strong>Cash Received</strong> – Total cash payments received.<br><em>Example:</em> $300</li><li><strong>Bank Received</strong> – Total bank payments received.<br><em>Example:</em> $200</li><li><strong>Total Received</strong> – Cash + Bank received.<br><em>Example:</em> $500</li><li><strong>Cash Given</strong> – Total cash payments given.<br><em>Example:</em> $50</li><li><strong>Bank Given</strong> – Total bank payments given.<br><em>Example:</em> $30</li><li><strong>Net Payments</strong> – Total Received – Total Given.<br><em>Example:</em> $500 - ($50+$30) = $420</li></ul><h2>Benefits</h2><ul><li>Provides a comprehensive daily overview of sales, purchases, and payments.</li><li>Helps track financial performance by showing totals, averages, and returns.</li><li>Ensures accurate reconciliation of cash and bank transactions.</li><li>Acts as an audit trail for compliance and reporting purposes.</li></ul>',CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:31:53.2887036' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
INSERT [dbo].[Pagehelpers] ([Id], [Code], [Name], [Description], [CreatedDate], [CreatedBy], [ModifiedDate], [ModifiedBy], [DeletedDate], [DeletedBy], [IsDeleted]) VALUES (N'339a06bd-fc9d-4bf8-8b9b-b8ca9b4868a5',N'ADD_LEDGER_ACCOUNT',N'Manage Ledger Account',N'<p>The <strong>Manage Ledger Account</strong> page allows users to create, edit, and manage ledger accounts in the accounting system. Each ledger account is linked to an account type and group for proper classification in financial reports.</p><hr><h2>Form Fields</h2><ul><li><strong>Account Code *</strong><br>Unique code for the ledger account. Must follow the company''s coding convention.<br><em>Example:</em> SAL001</li><li><strong>Account Name *</strong><br>Name of the ledger account.<br><em>Example:</em> Salary</li><li><strong>Account Type *</strong><br>Classification of the account. Options include: Asset, Liability, Equity, Income, Expense.<br><em>Example:</em> Expense</li><li><strong>Account Group *</strong><br>Grouping within the account type for reporting purposes.<br><em>Example:</em> Direct Expense</li><li><strong>Description</strong> (Optional)<br>Additional details about the account usage or purpose.<br><em>Example:</em> Monthly salary payments for staff</li></ul><h2>Tips & Notes</h2><ul><li>Ensure Account Code is unique across all accounts.</li><li>Choose Account Type and Group carefully, as it affects financial reporting.</li><li>Once transactions are posted to an account, modifying Account Type may impact reports.</li><li>Use descriptive Account Names to avoid confusion in journals and reports.</li></ul><h2>Benefits</h2><ul><li>Ensures proper classification of ledger accounts for accurate financial reporting.</li><li>Helps maintain organized accounting records and consistent groupings.</li><li>Enables smooth posting of transactions to the correct accounts.</li><li>Provides audit trail and reference for account setup and modifications.</li><li>Reduces errors in financial statements and reporting.</li></ul>',CAST(N'2025-02-04T10:14:13.0400000' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', CAST(N'2025-09-13T10:31:53.2887036' AS DateTime2), N'a29de04b-8668-4510-8107-13b7d5869736', NULL, NULL, 0)
